/* ============================================
   Auth Configuration
   Rate-limit constants for login attempts.
   Session management is handled by Supabase Auth.
   ============================================ */

/* ── Rate Limiting ───────────────────────── */

export const RATE_LIMIT = {
  MAX_ATTEMPTS: 5,
  WINDOW_MS: 60 * 1000, // 1 minute
  LOCKOUT_MS: 15 * 60 * 1000, // 15 minutes
} as const;

import { createSupabaseServerClient } from "@/lib/supabase/server";
import { userRepository } from "@/repositories/user.repository";
import {
  UnauthorizedError,
  ExpiredSessionError,
  ForbiddenError,
} from "@/lib/auth/errors";
import type { SessionUser, UserRole } from "@/types/auth";

/* ============================================
   Session Utilities
   Supabase Auth-based session management.
   Supabase manages the session cookies; we read
   the session and fetch the Prisma user profile.
   ============================================ */

/**
 * Get the currently authenticated user.
 *
 * Reads the Supabase session, then fetches the
 * corresponding Prisma User profile by supabaseUid.
 * Returns `null` if not authenticated.
 */
export async function getCurrentUser(): Promise<SessionUser> {
  const supabase = await createSupabaseServerClient();

  const {
    data: { user: supabaseUser },
  } = await supabase.auth.getUser();

  if (!supabaseUser) return null;

  const user = await userRepository.findBySupabaseUid(supabaseUser.id);

  if (!user) return null;

  return {
    id: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
    avatar: user.avatar,
  };
}

/**
 * Require an authenticated user.
 * Throws `UnauthorizedError` if no valid session exists.
 */
export async function requireUser(): Promise<NonNullable<SessionUser>> {
  const user = await getCurrentUser();

  if (!user) {
    throw new UnauthorizedError();
  }

  return user;
}

/**
 * Require the authenticated user to have one of the specified roles.
 * Throws `UnauthorizedError` if not logged in, `ForbiddenError` if
 * the user's role is not in the allowed list.
 */
export async function requireRole(
  ...allowedRoles: UserRole[]
): Promise<NonNullable<SessionUser>> {
  const user = await requireUser();

  if (!allowedRoles.includes(user.role)) {
    throw new ForbiddenError();
  }

  return user;
}

/**
 * @deprecated Supabase Auth manages the session automatically
 * via `signInWithPassword()`. This function is kept as a no-op
 * for backward compatibility with code that still imports it.
 */
export async function createSession(_user: {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
}): Promise<void> {
  // No-op — Supabase Auth manages session creation
}

/**
 * Destroy the session by signing out of Supabase Auth.
 */
export async function destroySession(): Promise<void> {
  const supabase = await createSupabaseServerClient();
  await supabase.auth.signOut();
}

import { requireRole } from "@/lib/auth/session";
import type { UserRole } from "@/types/auth";

/* ============================================
   Role Permissions & Route Guards
   ============================================ */

/**
 * Role hierarchy for reference:
 *
 * OWNER       — Full access (everything)
 * ADMIN       — Everything except owner settings
 * EDITOR      — Projects + Uploads only
 * MEDIA_BUYER — Read-only dashboard + Clients
 * PHOTOGRAPHER— Uploads only
 */

export type { UserRole };

/* ── Route Guard Helpers ─────────────────── */

/** Require the OWNER role. */
export function requireOwner() {
  return requireRole("OWNER");
}

/** Require OWNER or ADMIN. */
export function requireAdmin() {
  return requireRole("OWNER", "ADMIN");
}

/** Require OWNER, ADMIN, or EDITOR. */
export function requireEditor() {
  return requireRole("OWNER", "ADMIN", "EDITOR");
}

/** Require OWNER, ADMIN, or MEDIA_BUYER. */
export function requireMediaBuyer() {
  return requireRole("OWNER", "ADMIN", "MEDIA_BUYER");
}

/** Require OWNER, ADMIN, EDITOR, or PHOTOGRAPHER. */
export function requirePhotographer() {
  return requireRole("OWNER", "ADMIN", "EDITOR", "PHOTOGRAPHER");
}

/* ── Role Hierarchy (for reference) ──────── */

export const ROLE_HIERARCHY: readonly UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
  "CLIENT",
] as const;

/**
 * Check whether a role has sufficient privilege.
 * Lower index = higher privilege.
 */
export function hasMinimumRole(
  userRole: UserRole,
  minRole: UserRole
): boolean {
  const userIdx = ROLE_HIERARCHY.indexOf(userRole);
  const minIdx = ROLE_HIERARCHY.indexOf(minRole);
  return userIdx !== -1 && minIdx !== -1 && userIdx <= minIdx;
}

import { getCurrentUser, requireUser, requireRole } from "@/lib/auth/session";
import type { UserRole } from "@prisma/client";

/* ============================================
   RBAC Utilities
   Role-Based Access Control helpers.
   Use these to protect Server Actions.
   ============================================ */

/** All roles in the system. */
export const ALL_ROLES: UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
  "CLIENT",
];

/** Management roles — can access dashboard. */
export const MANAGEMENT_ROLES: UserRole[] = [
  "OWNER",
  "ADMIN",
  "EDITOR",
  "MEDIA_BUYER",
  "PHOTOGRAPHER",
];

/** Admin roles — full access. */
export const ADMIN_ROLES: UserRole[] = ["OWNER", "ADMIN"];

/** Check if a user has a specific role. */
export function hasRole(userRole: UserRole | undefined, ...roles: UserRole[]): boolean {
  if (!userRole) return false;
  return roles.includes(userRole);
}

/** Check if user is admin (OWNER or ADMIN). */
export function isAdmin(userRole: UserRole | undefined): boolean {
  return hasRole(userRole, "OWNER", "ADMIN");
}

/** Check if user is owner. */
export function isOwner(userRole: UserRole | undefined): boolean {
  return userRole === "OWNER";
}

/** Check if user can manage (admin or management). */
export function canManage(userRole: UserRole | undefined): boolean {
  return hasRole(userRole, ...MANAGEMENT_ROLES);
}

// ── Server-side guards ─────────────────────

/** Require any authenticated user. */
export async function requireAuth() {
  return requireUser();
}

/** Require admin (OWNER or ADMIN). */
export async function requireAdmin() {
  return requireRole("OWNER", "ADMIN");
}

/** Require management role (dashboard access). */
export async function requireManagement() {
  return requireRole(...MANAGEMENT_ROLES);
}

/** Get current user or null (for optional auth checks). */
export async function getOptionalUser() {
  return getCurrentUser();
}

import { RATE_LIMIT } from "@/lib/auth/config";
import { RateLimitExceededError } from "@/lib/auth/errors";

/* ============================================
   Rate Limiter
   In-memory rate limiting for login attempts.
   Tracks attempts per IP address within a sliding
   window. Suitable for single-instance deployments.
   ============================================ */

type AttemptRecord = {
  count: number;
  windowStart: number;
  lockedUntil: number;
};

const attempts = new Map<string, AttemptRecord>();

/**
 * Periodically prune stale entries to prevent memory leaks.
 * Runs on every check — O(n) but n is bounded by unique IPs
 * in the current window.
 */
function pruneStale(now: number): void {
  for (const [key, record] of attempts.entries()) {
    if (now > record.windowStart + RATE_LIMIT.WINDOW_MS && now > record.lockedUntil) {
      attempts.delete(key);
    }
  }
}

/**
 * Check if an IP is within the allowed rate limit.
 * Throws `RateLimitExceededError` if the limit is exceeded.
 *
 * @param key - Typically the client IP address.
 */
export function checkRateLimit(key: string): void {
  const now = Date.now();
  pruneStale(now);

  const record = attempts.get(key);

  if (record) {
    // Still in lockout period
    if (now < record.lockedUntil) {
      throw new RateLimitExceededError();
    }

    // Window has expired — reset
    if (now > record.windowStart + RATE_LIMIT.WINDOW_MS) {
      attempts.set(key, {
        count: 1,
        windowStart: now,
        lockedUntil: 0,
      });
      return;
    }

    // Within window — increment
    record.count++;

    if (record.count > RATE_LIMIT.MAX_ATTEMPTS) {
      record.lockedUntil = now + RATE_LIMIT.LOCKOUT_MS;
      throw new RateLimitExceededError();
    }
  } else {
    attempts.set(key, {
      count: 1,
      windowStart: now,
      lockedUntil: 0,
    });
  }
}

/**
 * Record a failed login attempt for a key.
 * This increments the counter for rate limiting.
 */
export function recordFailedAttempt(key: string): void {
  const now = Date.now();
  pruneStale(now);

  const record = attempts.get(key);

  if (record) {
    if (now > record.windowStart + RATE_LIMIT.WINDOW_MS) {
      attempts.set(key, {
        count: 1,
        windowStart: now,
        lockedUntil: 0,
      });
    } else {
      record.count++;
      if (record.count >= RATE_LIMIT.MAX_ATTEMPTS) {
        record.lockedUntil = now + RATE_LIMIT.LOCKOUT_MS;
      }
    }
  } else {
    attempts.set(key, {
      count: 1,
      windowStart: now,
      lockedUntil: 0,
    });
  }
}

/**
 * Clear rate-limit records for a key after a successful login.
 */
export function clearRateLimit(key: string): void {
  attempts.delete(key);
}

/* ── Test Utilities ──────────────────────── */

/**
 * Reset all rate-limit state. For testing only.
 */
export function _resetRateLimit(): void {
  attempts.clear();
}

/* ============================================
   Authentication & Authorization Errors
   Custom error classes for granular handling.
   ============================================ */

/** Base error for all auth-related failures. */
export class AuthError extends Error {
  constructor(
    message: string,
    public code: string
  ) {
    super(message);
    this.name = "AuthError";
  }
}

/** Thrown when email/password combination is invalid. */
export class InvalidCredentialsError extends AuthError {
  constructor(message = "البريد الإلكتروني أو كلمة المرور غير صحيحة") {
    super(message, "INVALID_CREDENTIALS");
    this.name = "InvalidCredentialsError";
  }
}

/** Thrown when no session exists or the user is not authenticated. */
export class UnauthorizedError extends AuthError {
  constructor(message = "يجب تسجيل الدخول للوصول إلى هذه الصفحة") {
    super(message, "UNAUTHORIZED");
    this.name = "UnauthorizedError";
  }
}

/** Thrown when the authenticated user lacks the required role. */
export class ForbiddenError extends AuthError {
  constructor(message = "ليس لديك صلاحية للوصول إلى هذه الصفحة") {
    super(message, "FORBIDDEN");
    this.name = "ForbiddenError";
  }
}

/** Thrown when a session token has expired or is otherwise invalid. */
export class ExpiredSessionError extends AuthError {
  constructor(message = "انتهت صلاحية الجلسة، يرجى تسجيل الدخول مرة أخرى") {
    super(message, "EXPIRED_SESSION");
    this.name = "ExpiredSessionError";
  }
}

/** Thrown when too many login attempts have been made. */
export class RateLimitExceededError extends AuthError {
  constructor(message = "تم تجاوز عدد محاولات تسجيل الدخول المسموح بها") {
    super(message, "RATE_LIMIT_EXCEEDED");
    this.name = "RateLimitExceededError";
  }
}

"use client";

import {
  createContext,
  useContext,
  useState,
  useCallback,
  type ReactNode,
} from "react";

import type { SessionUser, SessionStatus } from "@/types/auth";

type SessionContextValue = {
  user: SessionUser;
  status: SessionStatus;
  setUser: (user: SessionUser) => void;
  setStatus: (status: SessionStatus) => void;
};

const SessionContext = createContext<SessionContextValue | undefined>(
  undefined
);

export function SessionProvider({
  children,
  initialUser = null,
}: {
  children: ReactNode;
  initialUser?: SessionUser;
}) {
  const [user, setUser] = useState<SessionUser>(initialUser);
  const [status, setStatus] = useState<SessionStatus>(
    initialUser ? "authenticated" : "unauthenticated"
  );

  const handleSetUser = useCallback((value: SessionUser) => {
    setUser(value);
    setStatus(value ? "authenticated" : "unauthenticated");
  }, []);

  return (
    <SessionContext.Provider
      value={{ user, status, setUser: handleSetUser, setStatus }}
    >
      {children}
    </SessionContext.Provider>
  );
}

export function useSession() {
  const context = useContext(SessionContext);
  if (!context) {
    throw new Error("useSession must be used within a SessionProvider");
  }
  return context;
}

"use client";

import { useSession } from "@/providers/session-provider";

/**
 * Convenience hook for accessing session state.
 * Wraps `useSession` with derived booleans.
 */
export function useAuth() {
  const { user, status, setUser, setStatus } = useSession();

  return {
    user,
    status,
    isAuthenticated: status === "authenticated",
    isLoading: status === "loading",
    isUnauthenticated: status === "unauthenticated",
    setUser,
    setStatus,
  };
}

